SELECT

FROM mall_order
WHERE is_deleted = 0

    AND order_no = #{request.orderNo}


    AND pay_type = #{request.payType}


    AND order_status = #{request.orderStatus}


    AND delivery_type = #{request.deliveryType}


    AND receiver_name LIKE CONCAT('%', #{request.receiverName}, '%')


    AND receiver_phone LIKE CONCAT('%', #{request.receiverPhone}, '%')

ORDER BY create_time DESC

SELECT o.id, o.order_no, o.user_id, o.items_amount, o.total_amount, o.pay_amount, o.freight_amount, o.coupon_id, o.coupon_name, o.coupon_deduct_amount, o.coupon_consume_amount, o.coupon_waste_amount, o.coupon_snapshot_json, o.pay_type, o.order_status, o.delivery_type, o.address_id, o.receiver_name, o.receiver_phone, o.receiver_detail, o.note, o.pay_expire_time, o.refund_status, o.refund_time, o.refund_price, o.after_sale_flag, o.pay_time, o.paid, o.deliver_time, o.receive_time, o.finish_time, o.close_reason, o.close_time, o.remark, o.create_by, o.update_by, o.create_time, o.update_time, p.id AS product_id, COALESCE(p.name, first_item.product_name) AS product_name, first_item.quantity AS product_quantity, p.price AS product_price, c.name AS product_category, (SELECT pi.image_url FROM mall_product_image pi WHERE pi.product_id = p.id AND (pi.is_deleted IS NULL OR pi.is_deleted = 0) ORDER BY pi.sort ASC LIMIT 1) AS product_image FROM mall_order o LEFT JOIN ( SELECT oi.order_id, oi.product_id, oi.quantity, oi.product_name FROM mall_order_item oi WHERE (oi.is_deleted IS NULL OR oi.is_deleted = 0) AND oi.id = ( SELECT MIN(id) FROM mall_order_item moi WHERE moi.order_id = oi.order_id AND (moi.is_deleted IS NULL OR moi.is_deleted = 0) ) ) first_item ON o.id = first_item.order_id LEFT JOIN mall_product p ON first_item.product_id = p.id AND (p.is_deleted IS NULL OR p.is_deleted = 0) LEFT JOIN mall_category c ON p.category_id = c.id
(o.is_deleted IS NULL OR o.is_deleted = 0)
AND o.order_no = #{request.orderNo}
AND o.pay_type = #{request.payType}
AND o.order_status = #{request.orderStatus}
AND o.delivery_type = #{request.deliveryType}
AND o.receiver_name LIKE CONCAT('%', #{request.receiverName}, '%')
AND o.receiver_phone LIKE CONCAT('%', #{request.receiverPhone}, '%')
ORDER BY o.create_time DESC

SELECT o.id AS order_id, o.order_no, o.user_id, u.nickname AS user_nickname, u.phone_number AS user_phone_number, o.receiver_name, o.receiver_phone, o.receiver_detail, o.delivery_type, o.order_status, o.pay_type, o.items_amount, o.total_amount, o.pay_amount, o.freight_amount, o.coupon_id, o.coupon_name, o.coupon_deduct_amount, o.coupon_consume_amount, oi.id AS order_item_id, oi.product_id, oi.product_name, oi.image_url AS product_image, oi.price AS product_price, oi.quantity AS product_quantity, oi.total_price AS product_total_amount, oi.coupon_deduct_amount AS product_coupon_deduct_amount, oi.payable_amount AS product_payable_amount, o.create_time AS order_create_time FROM mall_order o LEFT JOIN `user` u ON u.id = o.user_id AND (u.is_delete IS NULL OR u.is_delete = 0) LEFT JOIN mall_order_item oi ON oi.order_id = o.id AND (oi.is_deleted IS NULL OR oi.is_deleted = 0) WHERE (o.is_deleted IS NULL OR o.is_deleted = 0) AND o.order_no IN
#{orderNo}
ORDER BY o.create_time DESC, oi.id
